import React from 'react';

function Achievements({ data }) {
  if (!data) return null;

  return (
    <section id="achievements" className="py-4 md:py-5 bg-[#f8fafc]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-2 md:mb-3">
          <p className="text-[8px] uppercase tracking-[0.35em] text-[#466978] font-semibold mb-1">
            Achievements
          </p>
          <h2 className="text-lg md:text-2xl font-black text-[#0f2f39] leading-tight">
            Awards and recognition
          </h2>
        </div>

        <div className="relative pl-1 md:pl-2">
          <div className="absolute left-0 md:left-1 top-0 bottom-0 w-px bg-[#b8cfda]" />

          <div className="space-y-1 md:space-y-2">
            {data.map((achievement, index) => (
              <article
                key={achievement.id}
                className="relative rounded-lg border border-[#c7d9e1] bg-white p-2 md:p-2 shadow-[0_4px_12px_rgba(15,47,57,0.08)]"
              >
                <span className="absolute -left-[16px] md:-left-[22px] top-5 h-2 w-2 rounded-full bg-[#0f4f61] ring-2 ring-[#f8fafc]" />

                <div className="flex flex-wrap items-start justify-between gap-2">
                  <div className="min-w-0">
                    <p className="text-[8px] uppercase tracking-[0.3em] text-[#5d808d] mb-1">
                      Achievement {String(index + 1).padStart(2, '0')}
                    </p>
                    <h3 className="text-sm md:text-base font-black text-[#0f2f39] leading-tight">
                      {achievement.title}
                    </h3>
                  </div>

                  <span className="inline-flex items-center rounded-full bg-[#e9f2f6] border border-[#c7d9e1] px-2 py-0.5 text-[8px] font-semibold uppercase tracking-[0.18em] text-[#1e4e5d]">
                    {achievement.year}
                  </span>
                </div>
              </article>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Achievements;
